// Получаем поле output от AI Agent
const raw = $input.item.json.output;

// Парсим — это строка с JSON внутри
const parsed = JSON.parse(raw);

return {
  json: {
    answer: parsed.answer,
    current_stage: parsed.current_stage,
    task_bank: parsed.task_bank ?? ""
  }
};

